function WorldMap({ countries, filter }) {
  // Generating SVG paths for 200 countries is CPU-intensive (~80ms measured in profiler).
  const filteredPaths = useMemo(
    () => countries
      .filter(c => c.region === filter)
      .map(c => generateSvgPath(c.coordinates)),
    [countries, filter]
  );

  return (
    <svg viewBox="0 0 1000 500">
      {filteredPaths.map((path, i) => <path key={i} d={path} />)}
    </svg>
  );
}
